"Here is a Java method to convert a string to title case while handling exceptions for certain words:

```java
public class TitleCaseConverter {
    private static final String[] EXCEPTION_WORDS = {"of", "the", "is", "and"};

    public static String convertToTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        StringBuilder result = new StringBuilder();
        boolean isFirstWord = true;

        for (int i = 0; i < input.length(); i++) {
            char currentChar = input.charAt(i);

            if (i == 0) {
                // First word should be capitalized
                result.append(Character.toUpperCase(currentChar));
                isFirstWord = false;
            } else {
                // Check if current character is a letter
                if (Character.isLetter(currentChar)) {
                    // Check if it's an exception word
                    if (isExceptionWord(currentChar, i, input)) {
                        result.append(currentChar);
                    } else {
                        // Capitalize the letter if it's not the first word and not an exception word
                        result.append(Character.toUpperCase(currentChar));
                    }
                } else {
                    // Non-letter characters are left as-is
                    result.append(currentChar);
                }
            }
        }

        return result.toString();
    }

    private static boolean isExceptionWord(char currentChar, int index, String input) {
        // Check if the current character is part of an exception word
        if (index == 0) {
            return false;
        }

        // Check if the current character is the first letter of an exception word
        for (String exception : EXCEPTION_WORDS) {
            if (index >= exception.length() && input.substring(index - exception.length()).equals(exception)) {
                return true;
            }
        }

        return false;
    }
}
```

